  const cacheSpy = jest.spyOn(cache, 'get');
  const authSpy = jest.spyOn(auth, 'validate');

  await request(app)
    .get('/projects/123')
    .set('Authorization', 'Bearer invalid-token');

  // Auth should be called before cache
  expect(authSpy).toHaveBeenCalledBefore(cacheSpy);
